def convert_messages_to_tokens_and_masks(messages, tokenizer, parser, contains_first_msg=False, contains_generation_msg=False):
    all_msg_tokens = []
    all_msg_masks = []

    def _convert(msg, first_msg=False, generation_msg=False):
        msg_text = parser.parse([msg], add_generation_prompt=generation_msg, is_first_msg=first_msg)
        if msg["role"] == "assistant" and msg_text.startswith(parser.assistant_token):
            msg_text = msg_text.replace(parser.assistant_token, "", 1)
        msg_tokens = tokenizer.encode(msg_text, add_special_tokens=False)
        mask_value = 1 if msg["role"] == "assistant" else 0
        return msg_tokens, [mask_value] * len(msg_tokens)

    for i, msg in enumerate(messages):
        tokens, mask = _convert(
            msg,
            first_msg=(contains_first_msg and i == 0),
            generation_msg=(contains_generation_msg and i == len(messages) - 1),
        )
        all_msg_tokens.extend(tokens)
        all_msg_masks.extend(mask)

    return all_msg_tokens, all_msg_masks

def eval_answer_to_float(answer_str):
    import math as _math
    answer_str = answer_str.strip()
    try:
        return float(answer_str)
    except ValueError:
        pass
    try:
        import sympy
        s = answer_str
        s = s.replace('\\frac{', '((').replace('}{', ')/(').replace('}', ')')
        s = s.replace('\\sqrt{', '_math.sqrt(')
        s = s.replace('\\pi', str(_math.pi))
        s = s.replace('^', '**')
        if s.count('(') > s.count(')'):
            s += ')' * (s.count('(') - s.count(')'))
        val = float(eval(s, {"__builtins__": {}}, {"_math": _math, "math": _math}))
        return val
    except Exception:
        pass
    try:
        import sympy
        expr = sympy.sympify(answer_str, evaluate=True)
        return float(expr.evalf())
    except Exception:
        return None


def deepscaler_reward_fn(prompts, completions, **kwargs):
    rewards = []
    answers = kwargs.get("answer", [])
    for i, (prompt, completion) in enumerate(zip(prompts, completions)):
        gt = answers[i] if i < len(answers) else None
        if isinstance(completion, list):
            text = " ".join(
                msg.get("content", "") for msg in completion if isinstance(msg, dict)
            )
        else:
            text = str(completion)
        numbers = re.findall(r'-?\d+\.?\d*', text)
        if not numbers or gt is None:
            rewards.append(0.0)
            continue
        predicted = float(numbers[-1])
        gt_val = eval_answer_to_float(str(gt))
        if gt_val is None:
            rewards.append(0.0)
        elif abs(predicted - gt_val) < max(1e-3, 1e-2 * abs(gt_val)):
            rewards.append(1.0)
        else:
            rel_err = abs(predicted - gt_val) / max(abs(gt_val), 1e-6)
            if rel_err < 0.1:
                rewards.append(0.5)
            elif rel_err < 0.5:
                rewards.append(0.2)
            else:
                rewards.append(0.0)
    return rewards


