            def calculate(nested_expr):
                return self._safe_eval(nested_expr)

            allowed_names = {
                "abs": abs,
                "binomial": math.comb,
                "calculate": calculate,
                "ceil": math.ceil,
                "comb": math.comb,
                "factorial": math.factorial,
                "floor": math.floor,
                "frac": lambda a, b: a / b,
                "sqrt": math.sqrt,
